select , category.name category_name from posts
left join category on posts.category_id = category.id
where posts.user_id=#{userID} and posts.id=#{articleId}

mapper.update:
UPDATE posts
JOIN category c ON c.user_id = #{p.userID}
SET draft_title = #{p.draftTitle},
  draft_content = #{p.draftContent},
  draft_updated_at = NOW(),
  category_id = #{p.categoryId}
WHERE
  posts.user_id = #{p.userID} and posts.id = #{p.id}

mapper.select:
select , category.name category_name from posts left join category on category.id = posts.category_id and category.user_id = posts.user_id WHERE posts.user_id = #{userID}
and (title like concat('%', #{keyword}, '%') or draft_title like concat('%', #{keyword}, '%'))
order by draft_updated_at desc
